// Parse sitemap XML and aggregate all articles into a single item
const xmlText = $input.first().json.data;

// Extract all <loc> URLs
const urlMatches = xmlText.match(/<loc>([^<]+)<\/loc>/g) || [];
const allUrls = urlMatches.map(m => m.replace(/<\/?loc>/g, '').trim());

// Filter to article URLs only (exclude sitemap index, homepage, etc.)
const articleUrls = allUrls.filter(url => {
  return (
    url.includes('ethicalbiohacking.com') &&
    !url.match(/sitemap/) &&
    !url.match(/\.xml$/) &&
    url.split('/').filter(Boolean).length >= 4
  );
});

// Category detection from URL path segments
const categorize = (url) => {
  const lower = decodeURIComponent(url).toLowerCase();
  if (lower.match(/sue[nñ]o|sleep/)) return 'Sueño';
  if (lower.match(/nutrici[oó]n|nutrition|dieta|diet/)) return 'Nutrición';
  if (lower.match(/ejercicio|exercise|fitness|entren/)) return 'Ejercicio';
  if (lower.match(/mente|mind|cogni|neuro|cerebro/)) return 'Mente';
  if (lower.match(/longevidad|longevity|aging|envejecimiento/)) return 'Longevidad';
  if (lower.match(/suplemento|supplement|nootropi/)) return 'Suplementos';
  if (lower.match(/ayuno|fasting/)) return 'Ayuno';
  if (lower.match(/hormona|hormone|testoster|cortisol/)) return 'Hormonas';
  if (lower.match(/estres|stress|cortisol/)) return 'Estrés';
  return 'Biohacking';
};

const hashtagMap = {
  'Sueño':       '#Sueño #SleepOptimization #Biohacking',
  'Nutrición':   '#Nutrición #NutriHacking #Biohacking',
  'Ejercicio':   '#Ejercicio #PerformanceHacking #Biohacking',
  'Mente':       '#Neurohacking #MindOptimization #Biohacking',
  'Longevidad':  '#Longevidad #Longevity #Biohacking',
  'Suplementos': '#Suplementos #Nootropics #Biohacking',
  'Ayuno':       '#AyunoIntermitente #Fasting #Biohacking',
  'Hormonas':    '#Hormonas #HormoneOptimization #Biohacking',
  'Estrés':      '#GestiónDelEstrés #StressHacking #Biohacking',
  'Biohacking':  '#Biohacking #EthicalBiohacking #Optimización'
};

const articles = articleUrls.map(url => {
  const category = categorize(url);
  return {
    url,
    category,
    hashtags: hashtagMap[category] || hashtagMap['Biohacking']
  };
});

console.log(`Sitemap parsed: ${articles.length} articles found`);

return [{ json: { articles } }];

