// Get all sitemap articles (from node-003 upstream)
const sitemapNode = $('🔍 Parsear & Categorizar Sitemap');
const articles = sitemapNode.first().json.articles;

// Get all published records from Postgres results
const publishedItems = $input.all();

const publishedUrls = new Set(
  publishedItems
    .filter(item => item.json && item.json.url)
    .map(item => item.json.url.trim())
);

// Get the LAST published category (most recent row)
// Postgres returns rows ordered by published_at ASC so last element = most recent
const lastPublishedItem = publishedItems
  .filter(item => item.json && item.json.category)
  .at(-1);

const lastCategory = lastPublishedItem?.json?.category || null;

console.log(`Published: ${publishedUrls.size} | Sitemap: ${articles.length} | Last category: ${lastCategory}`);

// Find FIRST unpublished article that is NOT from the last category
let newArticle = articles.find(a => !publishedUrls.has(a.url) && a.category !== lastCategory);

// Fallback: if all unpublished articles belong to the same last category, ignore the filter
if (!newArticle) {
  newArticle = articles.find(a => !publishedUrls.has(a.url));
}

if (!newArticle) {
  console.log('No new articles to publish.');
  return [{ json: { hasNew: false, url: null, category: null, hashtags: null } }];
}

console.log(`New article found: ${newArticle.url} | Category: ${newArticle.category}`);
return [{ json: { hasNew: true, ...newArticle } }];

// Extract metadata from raw HTML
const html = $input.first().json.data || '';

// Get context from upstream IF node
const context = $('¿Hay Novedades?').first().json;
const articleUrl = context.url;
const category   = context.category;
const hashtags   = context.hashtags;

// --- Title ---
const titleMatch = html.match(/<title[^>]*>([^<]+)<\/title>/i);
let title = titleMatch ? titleMatch[1] : '';
title = title.replace(/\s*[|\-–—]\s*[^|\-–—]{1,50}$/, '').trim();

// --- Meta Description ---
const descMatch =
  html.match(/<meta[^>]+name=["']description["'][^>]+content=["']([^"']+)["']/i) ||
  html.match(/<meta[^>]+content=["']([^"']+)["'][^>]+name=["']description["']/i) ||
  html.match(/<meta[^>]+property=["']og:description["'][^>]+content=["']([^"']+)["']/i);
const description = descMatch ? descMatch[1].trim() : '';

// --- First meaningful paragraphs ---
const paragraphs = [];
const pRegex = /<p[^>]*>(.*?)<\/p>/gi;
let match;
while ((match = pRegex.exec(html)) !== null) {
  const clean = match[1].replace(/<[^>]+>/g, '').trim();
  if (clean.length > 60) paragraphs.push(clean);
  if (paragraphs.length >= 4) break;
}
const firstParagraphs = paragraphs.join(' ').substring(0, 900);

// --- Image ---
const imgMatch = html.match(/<meta[^>]+property=["']og:image["'][^>]+content=["']([^"']+)["']/i);
const imageUrl = imgMatch ? imgMatch[1].trim() : '';

console.log(`Extracted - Title: "${title}" | Desc length: ${description.length} | Img: ${imageUrl} | Paragraphs: ${paragraphs.length}`);

return [{
  json: {
    url: articleUrl,
    category,
    hashtags,
    title,
    description,
    firstParagraphs,
    imageUrl
  }
}];

